const rawInput = $input.first().json || {};
const input = (rawInput.body && typeof rawInput.body === 'object' && (rawInput.body.triggered_action || rawInput.body.control_command)) ? rawInput.body : rawInput;
const action = input.triggered_action || input.control_command || {};
const payload = input.payload || {};
const cabin = payload.cabin || {};
const security = payload.security || {};
const maintenance = payload.maintenance || {};
const now = new Date().toISOString();

const minFloor = Number($env.MIN_FLOOR ?? 0);
const maxFloor = Number($env.MAX_FLOOR ?? 3);
const groundFloor = Number($env.GROUND_FLOOR ?? 0);
const maxRiskAutoControl = Number($env.MAX_RISK_AUTO_CONTROL ?? 85);
const thingId = input.thing_id || action.thing_id || input.control_command?.thing_id || $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const command = action.command;
const riskScore = Number(action.risk_score ?? input.risk_analysis?.risk_score ?? input.risk_score ?? 0);
const sourceAgent = action.source_agent || input.agent_source || input.metadata?.workflow || 'unknown_agent';
const reason = Array.isArray(action.reason) ? action.reason : [action.reason].filter(Boolean);
const commandId = action.command_id || `CMD-${thingId.replace(/[^a-zA-Z0-9]/g, '-')}-${Date.now()}`;
const providedCorrelationId = action.correlation_id || input.correlation_id;
const correlationId = providedCorrelationId || `CID-CTL-FALLBACK-${commandId}`;
const requestedBy = action.requested_by || sourceAgent;
const humanApproved = action.human_approved === true || action.approved_by;

const allowed = new Set([
  'EMERGENCY_STOP',
  'LOCKDOWN',
  'REPOSITION',
  'RESTRICT_LOAD',
  'MAINTENANCE_MODE',
  'RESUME_NORMAL',
  'FIRE_RECALL_TO_GROUND',
  'DOOR_HOLD_OPEN',
  'DOOR_CLOSE_SAFE',
  'SET_ENERGY_SAVING_MODE',
  'CLEAR_SECURITY_ALERT',
  'ACKNOWLEDGE_INCIDENT'
]);

const rejectionReasons = [];
const writes = [];
let label = command || 'UNKNOWN';

if (!allowed.has(command)) rejectionReasons.push(`UNSUPPORTED_COMMAND:${command || 'missing'}`);
if (!thingId) rejectionReasons.push('MISSING_THING_ID');
if (!providedCorrelationId) rejectionReasons.push('MISSING_CORRELATION_ID');
if (!sourceAgent) rejectionReasons.push('MISSING_SOURCE_AGENT');
if (reason.length === 0) rejectionReasons.push('MISSING_REASON');

const movementCommands = new Set(['REPOSITION', 'FIRE_RECALL_TO_GROUND']);
if (movementCommands.has(command) && input.system_mode === 'LOCKDOWN') rejectionReasons.push('MOVEMENT_BLOCKED_LOCKDOWN');
if (movementCommands.has(command) && cabin.emergency_stop) rejectionReasons.push('MOVEMENT_BLOCKED_EMERGENCY_STOP');

if (command === 'REPOSITION') {
  const targetFloor = Number(action.target_floor);
  if (!Number.isInteger(targetFloor) || targetFloor < minFloor || targetFloor > maxFloor) {
    rejectionReasons.push(`TARGET_FLOOR_OUT_OF_RANGE:${action.target_floor}`);
  } else {
    label = `Reposition elevator to floor ${targetFloor}`;
    writes.push({ path: 'features/cabin/properties/target_floor', value: targetFloor });
  }
}

if (command === 'RESUME_NORMAL') {
  const unresolvedCritical = security.active_security_incident ||
    String(security.alert_level || '').toUpperCase() === 'CRITICAL' ||
    maintenance.active_critical_issue === true ||
    input.risk_analysis?.severity === 'CRITICAL';
  if (unresolvedCritical && !humanApproved) rejectionReasons.push('RESUME_REQUIRES_HUMAN_CLEARANCE');
}

const criticalSafetyCommands = new Set(['EMERGENCY_STOP', 'LOCKDOWN', 'FIRE_RECALL_TO_GROUND']);
if (riskScore >= maxRiskAutoControl && !humanApproved && !criticalSafetyCommands.has(command)) {
  rejectionReasons.push('AUTO_CONTROL_REQUIRES_HUMAN_APPROVAL');
}

switch (command) {
  case 'EMERGENCY_STOP':
    label = 'Emergency stop asserted';
    writes.push({ path: 'features/cabin/properties/emergency_stop', value: true });
    writes.push({ path: 'attributes/system_mode', value: 'MAINTENANCE' });
    break;
  case 'LOCKDOWN':
    label = 'Security lockdown asserted';
    writes.push({ path: 'features/cabin/properties/emergency_stop', value: true });
    writes.push({ path: 'features/security/properties/alert_level', value: 'CRITICAL' });
    writes.push({ path: 'features/security/properties/active_security_incident', value: true });
    writes.push({ path: 'attributes/system_mode', value: 'LOCKDOWN' });
    break;
  case 'RESTRICT_LOAD':
    label = 'Restrict load pending manual clearance';
    writes.push({ path: 'features/cabin/properties/emergency_stop', value: true });
    writes.push({ path: 'features/cabin/properties/load_restricted', value: true });
    writes.push({ path: 'attributes/system_mode', value: 'MAINTENANCE' });
    break;
  case 'MAINTENANCE_MODE':
    label = 'Place elevator into maintenance mode';
    writes.push({ path: 'features/cabin/properties/emergency_stop', value: true });
    writes.push({ path: 'attributes/system_mode', value: 'MAINTENANCE' });
    break;
  case 'RESUME_NORMAL':
    label = 'Resume normal service';
    writes.push({ path: 'features/cabin/properties/emergency_stop', value: false });
    writes.push({ path: 'features/cabin/properties/load_restricted', value: false });
    writes.push({ path: 'attributes/system_mode', value: 'NORMAL' });
    break;
  case 'FIRE_RECALL_TO_GROUND':
    label = `Fire recall to floor ${groundFloor}`;
    writes.push({ path: 'features/cabin/properties/target_floor', value: groundFloor });
    writes.push({ path: 'features/fire_safety/properties/recall_active', value: true });
    writes.push({ path: 'attributes/system_mode', value: 'DEGRADED' });
    break;
  case 'DOOR_HOLD_OPEN':
    label = 'Hold door open for controlled access';
    writes.push({ path: 'features/door/properties/hold_open', value: true });
    break;
  case 'DOOR_CLOSE_SAFE':
    label = 'Request safe door close';
    writes.push({ path: 'features/door/properties/close_requested', value: true });
    writes.push({ path: 'features/door/properties/hold_open', value: false });
    break;
  case 'SET_ENERGY_SAVING_MODE':
    label = 'Enable energy saving mode';
    writes.push({ path: 'features/optimization/properties/energy_mode', value: 'SAVING' });
    break;
  case 'CLEAR_SECURITY_ALERT':
    label = 'Clear security alert after review';
    if (!humanApproved) rejectionReasons.push('CLEAR_SECURITY_ALERT_REQUIRES_HUMAN_APPROVAL');
    writes.push({ path: 'features/security/properties/active_security_incident', value: false });
    writes.push({ path: 'features/security/properties/alert_level', value: 'NORMAL' });
    break;
  case 'ACKNOWLEDGE_INCIDENT':
    label = 'Acknowledge active incident';
    writes.push({ path: 'features/security/properties/last_review_at', value: now });
    writes.push({ path: 'features/security/properties/human_review_required', value: false });
    break;
}

const status = rejectionReasons.length > 0 ? 'REJECTED' : 'VALIDATED';

return [{
  json: {
    ...input,
    control_command: {
      command_id: commandId,
      correlation_id: correlationId,
      thing_id: thingId,
      command,
      label,
      priority: action.priority || 'MEDIUM',
      requested_by: requestedBy,
      source_agent: sourceAgent,
      reason,
      risk_score: riskScore,
      status,
      issued_at: action.issued_at || now,
      validated_at: now,
      rejection_reasons: rejectionReasons,
      writes: status === 'VALIDATED' ? writes : []
    },
    control_rejected: status === 'REJECTED'
  }
}];

const input = $input.first().json || {};
const command = input.control_command || {};

if (command.status !== 'VALIDATED') {
  return [];
}

return (command.writes || []).map((write, index) => ({
  json: {
    ...input,
    write_index: index,
    thing_id: command.thing_id,
    correlation_id: command.correlation_id,
    command_id: command.command_id,
    command_name: command.command,
    command_label: command.label,
    command_status: 'DISPATCHED',
    path: write.path,
    value: write.value,
    issued_at: command.issued_at,
    audit_payload: {
      command_id: command.command_id,
      correlation_id: command.correlation_id,
      thing_id: command.thing_id,
      command: command.command,
      requested_by: command.requested_by,
      source_agent: command.source_agent,
      reason: command.reason,
      risk_score: command.risk_score,
      ditto_path: write.path,
      value: write.value
    }
  }
}));
